/* Types */
export type ApiVersionResponse = {
  version: string
  major: number
  minor: number
  patch: number
  codename: string
}

/**  认证配置（用户名/密码、密钥文件、Kerberos、OAuth2 等），密码字段已 AES-256-GCM 加密 */
export type AuthConfig = {
  id: string
  name: string | null
  auth_type: string
  auth_data: string
  origin: string | null
  source_id: string | null
  snapshot_at: string | null
  created_at: string
  updated_at: string
}

/**  批量评估表质量 — 一次调用完成全表所有列的质量评分 */
export type BatchEvaluateInput = {
  conn_id: string
  database: string
  schema: string
  table: string
}

export type BooleanStats = {
  true_count: number
  false_count: number
  true_ratio: number | null
}

/**
 *  缓存错误域
 *
 *  缓存操作相关的错误
 */
export type CacheError =
  /**  缓存未命中 */
  | ({
      Miss: {
        key: string
      }
    } & {
      Full?: never
      Internal?: never
      InvalidKey?: never
      InvalidValue?: never
      Serialization?: never
      Timeout?: never
    })
  /**  缓存已满 */
  | ({
      Full: {
        capacity: number
      }
    } & {
      Internal?: never
      InvalidKey?: never
      InvalidValue?: never
      Miss?: never
      Serialization?: never
      Timeout?: never
    })
  /**  缓存键无效 */
  | ({
      InvalidKey: {
        key: string
        reason: string
      }
    } & {
      Full?: never
      Internal?: never
      InvalidValue?: never
      Miss?: never
      Serialization?: never
      Timeout?: never
    })
  /**  缓存值无效 */
  | ({
      InvalidValue: {
        reason: string
      }
    } & {
      Full?: never
      Internal?: never
      InvalidKey?: never
      Miss?: never
      Serialization?: never
      Timeout?: never
    })
  /**  缓存操作超时 */
  | ({
      Timeout: {
        operation: string
        duration_ms: number
      }
    } & {
      Full?: never
      Internal?: never
      InvalidKey?: never
      InvalidValue?: never
      Miss?: never
      Serialization?: never
    })
  /**  缓存内部错误 */
  | ({
      Internal: {
        reason: string
      }
    } & {
      Full?: never
      InvalidKey?: never
      InvalidValue?: never
      Miss?: never
      Serialization?: never
      Timeout?: never
    })
  /**  缓存序列化错误 */
  | ({
      Serialization: {
        reason: string
      }
    } & {
      Full?: never
      Internal?: never
      InvalidKey?: never
      InvalidValue?: never
      Miss?: never
      Timeout?: never
    })

export type CacheStats = {
  l1_hits: number
  l1_misses: number
  l2_hits: number
  l2_misses: number
  db_queries: number
  l1_hit_avg_us: number
  l2_hit_avg_us: number
  db_query_avg_us: number
  l1_hit_rate: number | null
  l2_hit_rate: number | null
  overall_hit_rate: number | null
}

/**  缓存统计响应 */
export type CacheStatsResponse = {
  table_count: number
  column_count: number
  last_sync: number | null
}

/**  缓存状态响应 */
export type CacheStatusResponse = {
  is_valid: boolean
  last_sync: number | null
  stats: CacheStatsResponse | null
}

