/**  连接方式枚举 */
export type ConnectionMethod =
  /**  直接连接（无加密/无代理） */
  | 'direct'
  /**  SSL/TLS 加密连接 */
  | ({ ssl: SslConfig } & { chain?: never; http_proxy?: never; socks_proxy?: never; ssh?: never })
  /**  SSH 隧道连接 */
  | ({ ssh: SshConfig } & { chain?: never; http_proxy?: never; socks_proxy?: never; ssl?: never })
  /**  HTTP/HTTPS 代理连接 */
  | ({ http_proxy: ProxyConfig } & { chain?: never; socks_proxy?: never; ssh?: never; ssl?: never })
  /**  SOCKS4/5 代理连接 */
  | ({ socks_proxy: ProxyConfig } & { chain?: never; http_proxy?: never; ssh?: never; ssl?: never })
  /**  协议链路（外层 → 内层顺序，如 Proxy → SSH → SSL → DB） */
  | ({ chain: ChainHop[] } & { http_proxy?: never; socks_proxy?: never; ssh?: never; ssl?: never })

