/**
 *  核心错误容器
 *
 *  这是 Core 层统一的错误类型，采用"容器模式"包装各个错误域。
 *  每个错误域都是独立的枚举，避免 God Enum 问题。
 */
export type CoreError =
  /**  通用错误域 */
  | ({ Common: CommonError } & {
      Cache?: never
      Connection?: never
      Database?: never
      Plugin?: never
      Storage?: never
    })
  /**  连接错误域 */
  | ({ Connection: ConnectionError } & {
      Cache?: never
      Common?: never
      Database?: never
      Plugin?: never
      Storage?: never
    })
  /**  数据库错误域 */
  | ({ Database: DatabaseError } & {
      Cache?: never
      Common?: never
      Connection?: never
      Plugin?: never
      Storage?: never
    })
  /**  存储错误域 */
  | ({ Storage: StorageError } & {
      Cache?: never
      Common?: never
      Connection?: never
      Database?: never
      Plugin?: never
    })
  /**  缓存错误域 */
  | ({ Cache: CacheError } & {
      Common?: never
      Connection?: never
      Database?: never
      Plugin?: never
      Storage?: never
    })
  /**
   *  插件错误域
   *
   *  插件管理、加载、执行相关的所有错误
   */
  | ({ Plugin: PluginError } & {
      Cache?: never
      Common?: never
      Connection?: never
      Database?: never
      Storage?: never
    })

