/**
 *  存储错误域
 *
 *  持久化、序列化、IO 相关的错误
 */
export type StorageError =
  /**  持久化存储错误 */
  | ({
      Persistence: {
        store: string
        operation: string
        reason: string
      }
    } & { Deserialization?: never; Io?: never; Serialization?: never })
  /**  序列化错误 */
  | ({
      Serialization: {
        format: string
        reason: string
      }
    } & { Deserialization?: never; Io?: never; Persistence?: never })
  /**  反序列化错误 */
  | ({
      Deserialization: {
        format: string
        data: string
        reason: string
      }
    } & { Io?: never; Persistence?: never; Serialization?: never })
  /**  IO 错误（包含完整上下文） */
  | ({
      Io: {
        path: string
        operation: string
        reason: string
      }
    } & { Deserialization?: never; Persistence?: never; Serialization?: never })

